======================================================================This script performs automated compliance scanning across a target Organizational Unit (OU). It validates user settings against NIST SP 800-53 Rev. 5 (IA-2) controls by verifying that smart card authentication is explicitly mandated, checks for weak cryptographic settings, and exports an audit report.======================================================================<#.SYNOPSISEvaluates Active Directory user objects for FICAM and NIST SP 800-53, Rev. 5 compliance..DESCRIPTIONScans a target Organizational Unit (OU) to verify that Smart Card Logons are enforced, checks for missing altSecurityIdentities mappings, flags accounts with passwords that are set to never expire, and exports a CSV auditable report..PARAMETER TargetOUThe Distinguished Name (DN) of the OU containing the users to audit..PARAMETER ExportPathThe file path where the CSV compliance report should be saved..EXAMPLE.\Verify-FICAMCompliance.ps1 -TargetOU "OU=FederalUsers,DC=agency,DC=gov" -ExportPath "C:\Audit\FICAM_Report.csv"#>param([Parameter(Mandatory=$true, HelpMessage="Enter the Distinguished Name (DN) of the target OU.")][string]$TargetOU,[Parameter(Mandatory=$false)]	[string$ExportPath = ".\FICAM_Compliance_Report.csv")Ensure Active Directory module is availableif (-not (Get-Module -ListAvailable -Name ActiveDirectory)) {Write-Error "The Active Directory PowerShell module is required. Please install RSAT (Remote System Administration Tools)."exit 1}Import-Module ActiveDirectoryVerify the OU path existsif (-not (Get-ADOrganizationalUnit -Filter "DistinguishedName -eq '$TargetOU'"))Write-Error "The specified TargetOU path was not found: $TargetOU"exit 1}Write-Host "🔄 Starting FICAM Compliance Audit on: $TargetOU" -ForegroundColor CyanFetch target user accounts and critical attributes$users = Get-ADUser -SearchBase $TargetOU -Filter * -Properties UserAccountControl, altSecurityIdentities, CannotChangePassword, PasswordNeverExpires$complianceReport = @()$totalUsers = 0$nonCompliantCount = 0foreach ($user in $users) {$totalUsers++# 1. Evaluate Smart Card Requirement (userAccountControl bitwise 262144)	$smartCardEnforced = (($user.UserAccountControl -band 262144) -eq 262144)	# 2. Check for PIV Certificate Mapping	$hasCertMapping = ($null -ne $user.altSecurityIdentities -and $user.altSecurityIdentities.Count -gt 0)	# 3. Check for NIST Password Violations (Passwords should not be set to never expire if manual passwords are allowed)	$passwordNeverExpires = $user.PasswordNeverExpires	# Determine compliance status (NIST AAL3 / IA-2 baseline requires Smart Card + Cert Mapping)	$isCompliant = "COMPLIANT"	$failReasons = @()	if (-not $smartCardEnforced) {		$failReasons += "SmartCardNotRequired"		$isCompliant = "NON-COMPLIANT"	}	if (-not $hasCertMapping) {		$failReasons += "MissingAltSecurityIdentities"		$isCompliant = "NON-COMPLIANT"	}	if ($passwordNeverExpires -and -not $smartCardEnforced) {		$failReasons += "PasswordNeverExpiresWithoutMFA"		$isCompliant = "NON-COMPLIANT"	}		if ($isCompliant -eq "NON-COMPLIANT") {		$nonCompliantCount++	}	# Construct the report record	$reportRecord = [PSCustomObject]@{		SamAccountName		= $user.SamAccountName		DisplayName		= $user.DisplayName		SmartCardEnforced	= $smartCardEnforced		HasCertificateMapped	= $hasCertMapping		PasswordNeverExpires	= $passwordNeverExpires		Status			= $isCompliant		Violations		= ($failReasons -join " | ")	}	$complianceReport += $reportRecord}Export data to filetry {$complianceReport | Export-Csv -Path $ExportPath -NoTypeInformation -Encoding UTF8	# Calculate metrics	$complianceRate = [math]::Round((($totalUsers - $nonCompliantCount) / $totalUsers) * 100, 2)	Write-Host "`n📊 FICAM Audit Summary:" -ForegroundColor Baseline 	Write-Host "-----------------------------------------"	Write-Host "Total Accounts Audited : $totalUsers"	Write-Host "Non-Compliant Accounts : $nonCompliantCount" -ForegroundColor (If($nonCompliantCount -gt 0) {"Red"} Else {"Green"})	Write-Host "FICAM Pass Rate	   : $complianceRate%" -ForegroundColor (If($complianceRate -eq 100) {"Green"} Else {"Yellow"})	Write-Host "-----------------------------------------"	Write-Host "✅ Audit complete. Detailed report exported to: $ExportPath `n" -ForegroundColor Green}catch {Write-Error "Failed to export compliance log output to $ExportPath. Reason : $_"}